{
    "query": "query GetPatient($id: String!) {
  patient(id: $id) {
    id
    resourceType
    name {
      family
      given
      use
    }
    gender
    birthDate
    active
    telecom {
      system
      value
      use
    }
    address {
      line
      city
      state
      postalCode
      country
    }
  }
}",
    "variables": {
        "id": "test-patient-id"
    }
}

{
    "query": "query SearchPatients($name: String, $gender: String, $page: Int, $count: Int) {
  patients(name: $name, gender: $gender, page: $page, count: $count) {
    items {
      id
      resourceType
      name {
        family
        given
        use
      }
      gender
      birthDate
      active
    }
    total
    page
    count
  }
}",
    "variables": {
        "name": "Smith",
        "gender": "male",
        "page": 1,
        "count": 10
    }
}

{
    "query": "query GetAllPatients($page: Int, $count: Int) {
  allPatients(page: $page, count: $count) {
    items {
      id
      resourceType
      name {
        family
        given
        use
      }
      gender
      birthDate
      active
    }
    total
    page
    count
  }
}",
    "variables": {
        "page": 1,
        "count": 100
    }
}

{
    "query": "mutation CreatePatient($input: CreatePatientInput!) {\n  createPatient(input: $input) {\n    patient {\n      id\n      resourceType\n      name {\n        family\n        given\n      }\n      gender\n      birthDate\n      active\n    }\n  }\n}",
    "variables": {
        "input": {
            "name": [{
                "family": "Smith",
                "given": ["John"]
            }],
            "gender": "male",
            "birthDate": "1970-01-01",
            "active": true,
            "telecom": [{
                "system": "phone",
                "value": "555-123-4567",
                "use": "home"
            }],
            "address": [{
                "line": ["123 Main St"],
                "city": "Anytown",
                "state": "CA",
                "postalCode": "12345",
                "country": "USA"
            }]
        }
    }
}

{
    "query": "mutation UpdatePatient($id: String!, $input: UpdatePatientInput!) {\n  updatePatient(id: $id, input: $input) {\n    patient {\n      id\n      resourceType\n      name {\n        family\n        given\n      }\n      gender\n      birthDate\n      active\n    }\n  }\n}",
    "variables": {
        "id": "test-patient-id",
        "input": {
            "name": [{
                "family": "Smith",
                "given": ["John", "Adam"]
            }],
            "telecom": [{
                "system": "phone",
                "value": "555-987-6543",
                "use": "mobile"
            }]
        }
    }
}
